def total(price, quantity):
    if quantity < 0:
        raise ValueError('invalid quantity')
    return price * quantity

def fetch_page(size):
    if size < 1 or size > 100:
        raise ValueError('invalid page size')
    return list(range(size))

def add_item(state, item):
    state.append(item)
    return state

